<?php declare(strict_types=1);require __DIR__.'/../includes/functions.php';
class MathHelper{public static function add(float $a,float $b):float{return $a+$b;}}class AdvancedMath extends MathHelper{public static function power(float $a,float $b):float{return $a**$b;}}
$result=null;$expr='';$error='';if($_SERVER['REQUEST_METHOD']==='POST'){$a=filter_input(INPUT_POST,'a',FILTER_VALIDATE_FLOAT);$b=filter_input(INPUT_POST,'b',FILTER_VALIDATE_FLOAT);$op=(string)($_POST['operation']??'add');if($a===false||$b===false||$a===null||$b===null)$error='Vui lòng nhập hai số hợp lệ.';elseif($op==='power'&&abs($b)>100)$error='Số mũ phải từ -100 đến 100.';else{if($op==='power'){$result=AdvancedMath::power($a,$b);$expr="$a ^ $b";}else{$result=MathHelper::add($a,$b);$expr="$a + $b";}}}
$pageTitle='Bài 03 - Static';$basePath='..';$current='bai03';require __DIR__.'/../includes/header.php';?>
<div class="crumb"><a href="../index.php">Trang chủ</a> / Bài 03</div><h1>Static và kế thừa</h1><p class="subtitle">Gọi phương thức static trực tiếp mà không cần tạo object.</p><div class="two"><section class="card"><h2>Máy tính</h2><?php if($error):?><div class="alert err"><?=e($error)?></div><?php endif;?><form method="post"><div class="form-grid"><div class="group"><label>Số a</label><input type="number" step="any" name="a" value="<?=old('a','3')?>" required></div><div class="group"><label>Số b</label><input type="number" step="any" name="b" value="<?=old('b','5')?>" required></div><div class="group full"><label>Phép tính</label><select name="operation"><option value="add">Cộng</option><option value="power" <?=($_POST['operation']??'')==='power'?'selected':''?>>Lũy thừa</option></select></div></div><div class="actions"><button class="btn primary">Tính kết quả</button></div></form></section><aside class="card"><div class="result"><h2>Kết quả</h2><?php if($result!==null):?><div class="item"><div class="muted"><?=e($expr)?></div><div class="stat"><?=e((string)$result)?></div></div><?php else:?><p class="muted">Chưa thực hiện phép tính.</p><?php endif;?></div></aside></div><?php require __DIR__.'/../includes/footer.php';?>
